// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportWWContas-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&CtaBanCrt.IsEmpty() AND &CtaBanSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Nro Conta") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CtaBanCrt) WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Status") If Not &CtaBanSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = &CtaBanSts.EnumerationDescription() Endif EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'CTABANNOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CtaBanNom1.FromString(&GridStateDynamicFilter.Value) If not &CtaBanNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CtaBanNom1) EndIf Case &DynamicFiltersSelector1 = !'CTABANBANNOM' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CtaBanBanNom1.FromString(&GridStateDynamicFilter.Value) If not &CtaBanBanNom1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Banco", "Começa com") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Banco", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CtaBanBanNom1) EndIf Case &DynamicFiltersSelector1 = !'CTABANFILCOD' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &CtaBanFilCod1.FromString(&GridStateDynamicFilter.Value) If not &CtaBanFilCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator1 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Filial", "<") Case &DynamicFiltersOperator1 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Filial", "=") Case &DynamicFiltersOperator1 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Filial", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CtaBanFilCod1 EndIf Case &DynamicFiltersSelector1 = !'CTABANTIP' &CtaBanTip1.FromString(&GridStateDynamicFilter.Value) If not &CtaBanTip1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &CtaBanTip1.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CtaBanTip1.EnumerationDescription() Endif EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'CTABANNOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CtaBanNom2.FromString(&GridStateDynamicFilter.Value) If not &CtaBanNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CtaBanNom2) EndIf Case &DynamicFiltersSelector2 = !'CTABANBANNOM' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CtaBanBanNom2.FromString(&GridStateDynamicFilter.Value) If not &CtaBanBanNom2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Banco", "Começa com") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Banco", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CtaBanBanNom2) EndIf Case &DynamicFiltersSelector2 = !'CTABANFILCOD' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &CtaBanFilCod2.FromString(&GridStateDynamicFilter.Value) If not &CtaBanFilCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator2 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Filial", "<") Case &DynamicFiltersOperator2 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Filial", "=") Case &DynamicFiltersOperator2 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Filial", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CtaBanFilCod2 EndIf Case &DynamicFiltersSelector2 = !'CTABANTIP' &CtaBanTip2.FromString(&GridStateDynamicFilter.Value) If not &CtaBanTip2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &CtaBanTip2.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CtaBanTip2.EnumerationDescription() Endif EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'CTABANNOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CtaBanNom3.FromString(&GridStateDynamicFilter.Value) If not &CtaBanNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Nome", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CtaBanNom3) EndIf Case &DynamicFiltersSelector3 = !'CTABANBANNOM' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CtaBanBanNom3.FromString(&GridStateDynamicFilter.Value) If not &CtaBanBanNom3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Banco", "Começa com") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Banco", "Contém") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&CtaBanBanNom3) EndIf Case &DynamicFiltersSelector3 = !'CTABANFILCOD' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &CtaBanFilCod3.FromString(&GridStateDynamicFilter.Value) If not &CtaBanFilCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 Do Case Case &DynamicFiltersOperator3 = 0 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Filial", "<") Case &DynamicFiltersOperator3 = 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Filial", "=") Case &DynamicFiltersOperator3 = 2 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = format('%1 (%2)', "Filial", ">") EndCase &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &CtaBanFilCod3 EndIf Case &DynamicFiltersSelector3 = !'CTABANTIP' &CtaBanTip3.FromString(&GridStateDynamicFilter.Value) If not &CtaBanTip3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True If Not &CtaBanTip3.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &CtaBanTip3.EnumerationDescription() Endif EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Código" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Nome" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Filial" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Banco" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Banco" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Agência" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Nosso Número" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Dígito" &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "Status"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod CtabanCod using DSWWContas(&CtaBanCrt, &CtaBanSts, &DynamicFiltersSelector1, &DynamicFiltersOperator1, &CtaBanNom1, &CtaBanBanNom1 , &CtaBanFilCod1, &CtaBanTip1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &DynamicFiltersOperator2, &CtaBanNom2 , &CtaBanBanNom2, &CtaBanFilCod2, &CtaBanTip2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &DynamicFiltersOperator3 , &CtaBanNom3, &CtaBanBanNom3, &CtaBanFilCod3, &CtaBanTip3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = CtabanCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(CtaBanNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Number = CtaBanFilCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(CtaBanBanCod) &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = WWP_Export_SecureText(CtaBanBanNom) &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = CtaBanTip.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = WWP_Export_SecureText(CtaBanAgeCod) &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Number = CtaBanNosNro &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = WWP_Export_SecureText(CtaBanAgeDig) &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = CtaBanSts.EnumerationDescription()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWContasGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWContasGridState")) Else &GridState.FromXml(&Session.Get(!"WWContasGridState")) Endif
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"CTABANCRT" &CtaBanCrt.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"CTABANSTS" &CtaBanSts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
